                }
            };
        }
        else
        {
            readerSettings.DtdProcessing = DtdProcessing.Prohibit;
            readerSettings.XmlResolver = null;
        }

        readerSettings.MaxCharactersFromEntities = 1024 * 1024;
        readerSettings.MaxCharactersInDocument = 10 * 1024 * 1024;

        using (StringReader stringReader = new StringReader(xmlContent))
        using (XmlReader reader = XmlReader.Create(stringReader, readerSettings))
        {
            XmlDocument document = new XmlDocument();
            document.PreserveWhitespace = false;

            if (allowDtdProcessing)
            {
                document.XmlResolver = new XmlUrlResolver();
            }
            else
            {
                document.XmlResolver = null;
            }

            document.Load(reader);

            XmlNode root = document.DocumentElement;
            if (root == null)
            {
                throw new XmlException("XML document has no root element.");
            }

            ExtractSettings(root, string.Empty, settings);
        }

        return settings;
