    /// <summary>
    /// Parses an XML configuration file from a file path.
    /// </summary>
    /// <param name="filePath">Path to the XML configuration file</param>
    /// <param name="allowDtdProcessing">Whether to allow DTD processing</param>
    /// <returns>Dictionary containing configuration key-value pairs</returns>
    public Dictionary<string, string> ParseConfigurationFromFile(string filePath, bool allowDtdProcessing = true)
    {
        if (string.IsNullOrWhiteSpace(filePath))
        {
            throw new ArgumentException("File path cannot be null or empty.", nameof(filePath));
        }

        if (!File.Exists(filePath))
        {
            throw new FileNotFoundException("Configuration file not found.", filePath);
        }

        using (FileStream fileStream = new FileStream(filePath, FileMode.Open, FileAccess.Read))
        {
            string baseUri = new Uri(Path.GetFullPath(filePath)).AbsoluteUri;
            return ParseConfigurationFromStream(fileStream, baseUri, allowDtdProcessing);
        }
    }

    /// <summary>
    /// Recursively extracts settings from XML nodes into the dictionary.
    /// Builds hierarchical keys using dot notation (e.g., "database.connection.host").
    /// </summary>
    private void ExtractSettings(XmlNode node, string prefix, Dictionary<string, string> settings)
    {
        if (node == null) return;

        // Extract attributes of the current node
        if (node.Attributes != null)
        {
            foreach (XmlAttribute attr in node.Attributes)
            {
                string attrKey = string.IsNullOrEmpty(prefix)
                    ? $"{node.Name}.{attr.Name}"
                    : $"{prefix}.{node.Name}.{attr.Name}";

                AddOrUpdateSetting(settings, attrKey, attr.Value);
            }
        }

        // Check if this is a leaf node (contains only text, no child elements)
        bool hasChildElements = false;
        if (node.HasChildNodes)
        {
            foreach (XmlNode child in node.ChildNodes)
            {
                if (child.NodeType == XmlNodeType.Element)
                {
                    hasChildElements = true;
                    break;
                }
            }
        }

        if (!hasChildElements)
        {
            // Leaf node - extract the text value
            string textContent = node.InnerText?.Trim();
            if (textContent != null)
            {
                string key = string.IsNullOrEmpty(prefix) ? node.Name : $"{prefix}.{node.Name}";

                // Handle "key" and "value" pattern: <setting key="name" value="val"/>
                string keyAttr = node.Attributes?["key"]?.Value;
                string valueAttr = node.Attributes?["value"]?.Value;

                if (!string.IsNullOrEmpty(keyAttr))
                {
                    string settingKey = string.IsNullOrEmpty(prefix)
                        ? keyAttr
                        : $"{prefix}.{keyAttr}";
                    AddOrUpdateSetting(settings, settingKey, valueAttr ?? textContent);
                }
                else if (!string.IsNullOrEmpty(textContent))
                {
                    AddOrUpdateSetting(settings, key, textContent);
                }
            }
        }
        else
        {
            // Has child elements - recurse
            string newPrefix = string.IsNullOrEmpty(prefix) ? node.Name : $"{prefix}.{node.Name}";

            // Check for key/value pattern at this level too
            string keyAttr = node.Attributes?["key"]?.Value;
            if (!string.IsNullOrEmpty(keyAttr))
            {
                newPrefix = string.IsNullOrEmpty(prefix) ? keyAttr : $"{prefix}.{keyAttr}";
            }

            // Track duplicate element names for indexing
            var elementCounts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

            foreach (XmlNode child in node.ChildNodes)
            {
                if (child.NodeType == XmlNodeType.Element)
                {
                    if (!elementCounts.ContainsKey(child.Name))
                    {
                        elementCounts[child.Name] = 0;
                    }
                    elementCounts[child.Name]++;
                }
            }

            var elementIndices = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

            foreach (XmlNode child in node.ChildNodes)
            {
                if (child.NodeType == XmlNodeType.Element)
                {
                    if (elementCounts.ContainsKey(child.Name) && elementCounts[child.Name] > 1)
                    {
                        // Multiple elements with same name - use index
                        if (!elementIndices.ContainsKey(child.Name))
                        {
                            elementIndices[child.Name] = 0;
                        }

                        string indexedPrefix = $"{newPrefix}.{child.Name}[{elementIndices[child.Name]}]";
                        elementIndices[child.Name]++;

                        ExtractIndexedSettings(child, indexedPrefix, settings);
                    }
                    else
                    {
                        ExtractSettings(child, newPrefix, settings);
                    }
                }
                else if (child.NodeType == XmlNodeType.Text || child.NodeType == XmlNodeType.CDATA)
                {
                    string text = child.Value?.Trim();
                    if (!string.IsNullOrEmpty(text))
                    {
                        AddOrUpdateSetting(settings, newPrefix, text);
                    }
                }
            }
        }
    }

    /// <summary>
